135→pub async fn get_next_actions(
136→    AuthenticatedUser(user_id): AuthenticatedUser,
137→    State(pool): State<PgPool>,
138→    Query(filter): Query<ContextFilter>,
139→) -> Result<impl IntoResponse, NextActionError> {
140→    let inbox_count = inbox_service::get_inbox_count(&pool, &user_id)
141→        .await
142→        .map_err(NextActionError::Unexpected)?;
143→
144→    let contexts = context_service::list_contexts(&pool, &user_id)
145→        .await
146→        .map_err(NextActionError::Unexpected)?;
147→
148→    let actions = if let Some(ctx_uuid) = filter.context {
149→        let ctx_id = ContextId::from_uuid(ctx_uuid);
150→        next_action_service::list_active_next_actions_by_context(&pool, &user_id, &ctx_id)
151→            .await
152→            .map_err(NextActionError::Unexpected)?
153→    } else {
154→        next_action_service::list_active_next_actions(&pool, &user_id)
155→            .await
156→            .map_err(NextActionError::Unexpected)?
157→    };
158→
159→    let groups = build_context_groups(&actions, &contexts, filter.context.is_some());
160→
161→    let context_options: Vec<ContextOption> = contexts
162→        .iter()
163→        .map(|c| ContextOption {
164→            id: c.id().as_uuid().to_string(),
165→            name: c.name().as_str().to_string(),
166→        })
167→        .collect();
168→
169→    let selected_context = filter.context.map(|c| c.to_string());
170→
171→    let template = NextActionsTemplate {
172→        current_page: "next_actions",
173→        inbox_count,
174→        groups,
175→        contexts: context_options,
176→        selected_context,
177→        error_message: None,
178→    };
179→    Ok(Html(template.render()?))
180→}
