188→pub async fn post_next_action(
189→    AuthenticatedUser(user_id): AuthenticatedUser,
190→    State(pool): State<PgPool>,
191→    headers: HeaderMap,
192→    Form(form): Form<AddNextActionForm>,
193→) -> Result<Response, NextActionError> {
194→    let htmx = is_htmx_request(&headers);
195→
196→    if form.title.trim().is_empty() {
197→        if htmx {
198→            return Ok(StatusCode::NO_CONTENT.into_response());
199→        }
200→        return Ok(Redirect::to("/next-actions").into_response());
201→    }
202→
203→    let context_id = ContextId::from_uuid(form.context_id);
204→
205→    let contexts = context_service::list_contexts(&pool, &user_id)
206→        .await
207→        .map_err(NextActionError::Unexpected)?;
208→
209→    match next_action_service::add_next_action(&pool, user_id.clone(), context_id, form.title).await
210→    {
211→        Ok(action) => {
212→            if htmx {
213→                let template = NextActionItemTemplate {
214→                    action: build_action_view(&action, &contexts),
215→                };
216→                let body = template.render().map_err(NextActionError::Render)?;
217→                Ok(htmx_response_with_announce(Html(body), "Next action added"))
218→            } else {
219→                Ok(Redirect::to("/next-actions").into_response())
220→            }
221→        }
222→        Err(AddNextActionError::InvalidTitle(title_err)) => {
223→            let user_facing = match title_err {
224→                TodoTitleError::Empty => {
225→                    if htmx {
226→                        return Ok(StatusCode::NO_CONTENT.into_response());
227→                    }
228→                    return Ok(Redirect::to("/next-actions").into_response());
229→                }
230→                TodoTitleError::TooLong { max, .. } => {
231→                    format!("That title is too long (max {max} characters)")
232→                }
233→            };
234→
235→            render_next_actions_with_error(&pool, &user_id, &user_facing).await
236→        }
237→        Err(AddNextActionError::Unexpected(err)) => Err(NextActionError::Unexpected(err)),
238→    }
239→}
